int robLinear(vector<int>& nums, int start, int end)
{
    int prev2 = 0, prev1 = 0;
    for (int i = start; i <= end; i++)
    {
        int current = max(prev1, prev2 + nums[i]);
        prev2 = prev1;
        prev1 = current;
    }
